arguments.content:
$configPath = "$env:USERPROFILE\.openclaw\openclaw.json"
$config = Get-Content $configPath -Raw | ConvertFrom-Json

# Add plugins.allow if not present
if (-not $config.plugins.allow) {
    $config.plugins | Add-Member -MemberType NoteProperty -Name 'allow' -Value @('feishu') -Force
} else {
    $config.plugins.allow = @('feishu')
}

$config | ConvertTo-Json -Depth 10 | Set-Content $configPath -Encoding UTF8
Write-Output "plugins.allow set to: feishu"
